BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?partName ?partType WHERE {
  ?elem vocab:NamedElement_name ?ename .
  FILTER(CONTAINS(LCASE(STR(?ename)), "procedure executive and analysis software"))
  ?elem rdf:type vocab:block .
  ?elem vocab:StructuredClassifier_part ?part .
  OPTIONAL { ?part vocab:NamedElement_name ?partName . }
  OPTIONAL {
    ?part vocab:TypedElement_type ?typeElem .
    ?typeElem vocab:NamedElement_name ?partType .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?childName ?childType WHERE {
  <TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::Components::Procedure%2520Executive%2520and%2520Analysis%2520Software> vocab:Element_ownedElement ?child .
  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?superClassName ?behaviorName ?ownerName WHERE {
  ?elem vocab:NamedElement_name ?ename .
  FILTER(CONTAINS(STR(?ename), "Procedure") && CONTAINS(STR(?ename), "Analysis"))
  ?elem rdf:type vocab:block .
  ?elem ?prop ?val .
  FILTER(?prop IN (
    vocab:Class_superClass,
    vocab:BehavioredClassifier_classifierBehavior,
    vocab:Element_owner
  ))
  OPTIONAL { ?val vocab:NamedElement_name ?superClassName . FILTER(?prop = vocab:Class_superClass) }
  OPTIONAL { ?val vocab:NamedElement_name ?behaviorName . FILTER(?prop = vocab:BehavioredClassifier_classifierBehavior) }
  OPTIONAL { ?val vocab:NamedElement_name ?ownerName . FILTER(?prop = vocab:Element_owner) }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?stateName ?stateType WHERE {
  VALUES ?region {
    <TMT/region/_18_0_4_baa02e2_1436202327885_30489_145913>
    <TMT/region/_17_0_2_3_41e01aa_1383540424302_569319_58122>
  }
  ?region vocab:Region_subvertex ?state .
  ?state vocab:NamedElement_name ?stateName .
  OPTIONAL { ?state rdf:type ?stateType . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?stateName ?stateType WHERE {
  ?state vocab:Vertex_container ?region .
  VALUES ?region {
    <TMT/region/_18_0_4_baa02e2_1436202327885_30489_145913>
    <TMT/region/_17_0_2_3_41e01aa_1383540424302_569319_58122>
  }
  ?state vocab:NamedElement_name ?stateName .
  ?state rdf:type ?stateType .
}
LIMIT 25
